/* ===================================================
   STORAGE — persistência local dos orçamentos
   =================================================== */
class OrcamentoStorage {
  static #KEY = 'efv_solar_orcamentos';

  static listar() {
    try {
      return JSON.parse(localStorage.getItem(this.#KEY) ?? '[]');
    } catch { return []; }
  }

  static salvar(item) {
    const lista = this.listar();
    lista.unshift(item);
    localStorage.setItem(this.#KEY, JSON.stringify(lista));
  }

  static remover(id) {
    const lista = this.listar().filter(i => i.id !== id);
    localStorage.setItem(this.#KEY, JSON.stringify(lista));
  }

  static marcarOk(id) {
    const lista = this.listar().map(i => i.id === id ? { ...i, ok: true } : i);
    localStorage.setItem(this.#KEY, JSON.stringify(lista));
  }
}

/* ===================================================
   MENU HAMBURGER
   =================================================== */
class MenuController {
  #btn;
  #sidebar;
  #overlay;
  #isOpen = false;

  constructor() {
    this.#btn     = document.getElementById('btn-menu');
    this.#sidebar = document.getElementById('sidebar');
    this.#overlay = document.getElementById('menu-overlay');
    this.#bind();
  }

  #bind() {
    this.#btn.addEventListener('click', () => this.#toggle());
    this.#overlay.addEventListener('click', () => this.#fechar());
    document.addEventListener('keydown', e => { if (e.key === 'Escape') this.#fechar(); });
  }

  #toggle() {
    this.#isOpen ? this.#fechar() : this.#abrir();
  }

  #abrir() {
    this.#isOpen = true;
    this.#sidebar.classList.add('is-open');
    this.#sidebar.setAttribute('aria-hidden', 'false');
    this.#overlay.classList.add('is-visible');
    this.#overlay.setAttribute('aria-hidden', 'false');
    this.#btn.classList.add('is-open');
    this.#btn.setAttribute('aria-expanded', 'true');
    this.#btn.setAttribute('aria-label', 'Fechar menu');
  }

  fechar() { this.#fechar(); }

  #fechar() {
    this.#isOpen = false;
    this.#sidebar.classList.remove('is-open');
    this.#sidebar.setAttribute('aria-hidden', 'true');
    this.#overlay.classList.remove('is-visible');
    this.#overlay.setAttribute('aria-hidden', 'true');
    this.#btn.classList.remove('is-open');
    this.#btn.setAttribute('aria-expanded', 'false');
    this.#btn.setAttribute('aria-label', 'Abrir menu');
  }
}

/* ===================================================
   ROUTER — troca de telas
   =================================================== */
class Router {
  #telaAtual = 'home';
  #onTela;

  constructor(onTela) {
    this.#onTela = onTela;
    this.#bind();
  }

  #bind() {
    document.querySelectorAll('[data-tela]').forEach(btn => {
      btn.addEventListener('click', () => this.navegar(btn.dataset.tela));
    });
  }

  navegar(tela) {
    if (tela === this.#telaAtual) return;
    document.getElementById(`tela-${this.#telaAtual}`)?.classList.remove('tela--ativa');
    document.getElementById(`tela-${tela}`)?.classList.add('tela--ativa');

    document.querySelectorAll(`[data-tela="${this.#telaAtual}"]`)
      .forEach(b => b.classList.remove('sidebar-nav-item--ativo', 'bnav-item--ativo'));
    document.querySelectorAll(`[data-tela="${tela}"]`)
      .forEach(b => b.classList.add(
        b.closest('.sidebar-nav') ? 'sidebar-nav-item--ativo' : 'bnav-item--ativo'
      ));

    this.#telaAtual = tela;
    this.#onTela(tela);
  }

  get atual() { return this.#telaAtual; }
}

/* ===================================================
   TELA ORÇAMENTOS
   =================================================== */
class OrcamentosController {
  #container;
  #logoBase64;
  #shareCtrl = null;

  constructor(logoBase64) {
    this.#container  = document.getElementById('lista-orcamentos');
    this.#logoBase64 = logoBase64;
  }

  setShareCtrl(ctrl) { this.#shareCtrl = ctrl; }

  render() {
    const lista = OrcamentoStorage.listar();
    if (!lista.length) {
      this.#container.innerHTML = `
        <div class="lista-vazia">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round">
            <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/>
            <polyline points="14 2 14 8 20 8"/>
          </svg>
          <p>Nenhum orçamento salvo ainda.<br>Preencha o formulário e clique em <strong>Salvar e Gerar PDF</strong>.</p>
        </div>`;
      return;
    }
    this.#container.innerHTML = lista.map(o => this.#renderCard(o)).join('');
    this.#bindAcoes();
  }

  #renderCard(o) {
    return `
      <div class="orc-card" data-id="${o.id}">
        <div class="orc-card-info">
          <div class="orc-card-nome">${OrcamentosController.#esc(o.nome || 'Sem nome')}</div>
          <div class="orc-card-data">${o.data}</div>
        </div>
        <div class="orc-card-actions">
          <button class="btn-icon btn-icon--share" title="Compartilhar" data-acao="share" data-id="${o.id}">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
              <circle cx="18" cy="5" r="3"/><circle cx="6" cy="12" r="3"/><circle cx="18" cy="19" r="3"/>
              <line x1="8.59" y1="13.51" x2="15.42" y2="17.49"/>
              <line x1="15.41" y1="6.51" x2="8.59" y2="10.49"/>
            </svg>
          </button>
          <button class="btn-icon btn-icon--pdf" title="Abrir PDF" data-acao="pdf" data-id="${o.id}">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
              <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/>
              <polyline points="14 2 14 8 20 8"/>
              <line x1="16" y1="13" x2="8" y2="13"/>
              <line x1="16" y1="17" x2="8" y2="17"/>
            </svg>
          </button>
          <button class="btn-icon btn-icon--del" title="Apagar" data-acao="del" data-id="${o.id}">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">
              <polyline points="3 6 5 6 21 6"/>
              <path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/>
              <path d="M10 11v6M14 11v6"/>
              <path d="M9 6V4h6v2"/>
            </svg>
          </button>
        </div>
      </div>`;
  }

  #bindAcoes() {
    this.#container.querySelectorAll('[data-acao]').forEach(btn => {
      btn.addEventListener('click', () => {
        const { acao, id } = btn.dataset;
        if (acao === 'del') {
          if (confirm('Apagar este orçamento?')) {
            OrcamentoStorage.remover(id);
            this.render();
          }
        } else if (acao === 'pdf') {
          const item = OrcamentoStorage.listar().find(o => o.id === id);
          if (item) this.#abrirPDF(item);
        } else if (acao === 'share') {
          const item = OrcamentoStorage.listar().find(o => o.id === id);
          if (item && this.#shareCtrl) {
            const html = PrintBuilder.build(item.dados, this.#logoBase64);
            this.#shareCtrl.abrir(html, item.nome || 'Orçamento');
          }
        }
      });
    });
  }

  #abrirPDF(item) {
    const html = PrintBuilder.build(item.dados, this.#logoBase64);
    const win  = window.open('', '_blank');
    if (!win) { alert('Permita pop-ups para abrir o PDF.'); return; }
    win.document.write(html);
    win.document.close();
    win.addEventListener('load', () => setTimeout(() => win.print(), 400));
  }

  static #esc(str) {
    return String(str)
      .replace(/&/g,'&amp;').replace(/</g,'&lt;')
      .replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }
}

/* ===================================================
   TELA FINANÇAS
   =================================================== */
class FinancasController {
  #container;
  #elMensal;
  #elInvestimento;
  #elAnual;

  constructor() {
    this.#container      = document.getElementById('lista-financas');
    this.#elMensal       = document.getElementById('total-mensal');
    this.#elInvestimento = document.getElementById('total-investimento');
    this.#elAnual        = document.getElementById('total-anual');
  }

  render() {
    const lista = OrcamentoStorage.listar();
    if (!lista.length) {
      this.#container.innerHTML = '<div class="lista-vazia"><p>Nenhum orçamento salvo.</p></div>';
      this.#atualizarTotais([]);
      return;
    }
    this.#container.innerHTML = lista.map(o => this.#renderCard(o)).join('');
    this.#bindOk();
    this.#atualizarTotais(lista.filter(o => o.ok));
  }

  #renderCard(o) {
    return `
      <div class="fin-card" data-id="${o.id}">
        <div class="fin-card-info">
          <div class="fin-card-nome">${FinancasController.#esc(o.nome || 'Sem nome')}</div>
          <div class="fin-card-valor">
            Mensal: ${FinancasController.#esc(o.economia_mensal || '—')} &nbsp;|
            Investimento: ${FinancasController.#esc(o.investimento || '—')}
          </div>
        </div>
        <button class="btn-ok${o.ok ? ' is-ok' : ''}" data-id="${o.id}" ${o.ok ? 'disabled' : ''}>
          ${o.ok ? '✔ OK' : 'OK'}
        </button>
      </div>`;
  }

  #bindOk() {
    this.#container.querySelectorAll('.btn-ok:not([disabled])').forEach(btn => {
      btn.addEventListener('click', () => {
        OrcamentoStorage.marcarOk(btn.dataset.id);
        this.render();
      });
    });
  }

  #atualizarTotais(confirmados) {
    const somar = campo => confirmados.reduce((acc, o) => acc + FinancasController.#parseBRL(o[campo]), 0);
    const mensal      = somar('economia_mensal');
    const investimento = somar('investimento');
    const anual       = somar('economia_anual');
    this.#elMensal.textContent       = FinancasController.#fmt(mensal);
    this.#elInvestimento.textContent = FinancasController.#fmt(investimento);
    this.#elAnual.textContent        = FinancasController.#fmt(anual);
  }

  static #parseBRL(str) {
    if (!str) return 0;
    const n = parseFloat(
      String(str).replace(/R\$\s*/g,'').replace(/\./g,'').replace(',','.')
    );
    return isNaN(n) ? 0 : n;
  }

  static #fmt(v) {
    return v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  }

  static #esc(str) {
    return String(str)
      .replace(/&/g,'&amp;').replace(/</g,'&lt;')
      .replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }
}

/* ===================================================
   TARIFA SERVICE — busca tarifa Enel SP com cache
   =================================================== */
class TarifaService {
  /* URL CORS proxy para a API ANEEL/ANNEL Open Data.
     Como o app roda em file://, usamos um proxy CORS público.
     Fallback hardcoded = tarifa mai/2026 Enel SP TUSD+TE. */
  static #FALLBACK     = 0.982;
  static #CACHE_KEY    = 'efv_tarifa_cache';
  static #CACHE_TTL_MS = 24 * 60 * 60 * 1000; /* 24 h */

  static async obter() {
    /* 1. cache local ainda válido? */
    try {
      const raw = localStorage.getItem(TarifaService.#CACHE_KEY);
      if (raw) {
        const { valor, ts } = JSON.parse(raw);
        if (Date.now() - ts < TarifaService.#CACHE_TTL_MS) {
          return { valor, fonte: 'cache' };
        }
      }
    } catch { /* ignore */ }

    /* 2. tenta buscar via CORS proxy */
    try {
      /* API pública ANEEL — tabela de tarifas distribuidoras
         Filtra por distribuidora Enel SP (SigAgente=EDP SP) subgrupo B1 */
      const url = 'https://corsproxy.io/?' +
        encodeURIComponent(
          'https://dadosabertos.aneel.gov.br/api/3/action/datastore_search?' +
          'resource_id=b1bd71e7-d0ad-4214-9053-cbd58e9564a7&limit=5&' +
          'filters={"SigAgente":"EDP SP","DscSubGrupo":"B1","DscModalidadeTarifaria":"Convencional"}&' +
          'sort=DatInicioVigencia+desc'
        );
      const res  = await fetch(url, { signal: AbortSignal.timeout(5000) });
      const json = await res.json();
      const rec  = json?.result?.records?.[0];
      /* VlrTE + VlrTUSD = tarifa total kWh */
      const te   = parseFloat(rec?.VlrTE   ?? 0);
      const tusd = parseFloat(rec?.VlrTUSD ?? 0);
      if (te > 0 && tusd > 0) {
        const valor = +(te + tusd).toFixed(4);
        localStorage.setItem(TarifaService.#CACHE_KEY,
          JSON.stringify({ valor, ts: Date.now() }));
        return { valor, fonte: 'api' };
      }
    } catch { /* rede indisponível ou proxy falhou */ }

    /* 3. fallback hardcoded */
    return { valor: TarifaService.#FALLBACK, fonte: 'fallback' };
  }

  static formatar(v) {
    return 'R$ ' + v.toFixed(3).replace('.', ',');
  }
}

/* ===================================================
   TELA CALCULADORA SOLAR
   =================================================== */
class CalculadoraController {
  static #CRESCIMENTO_DEFAULT = 0.06;
  static #TARIFA_KWH  = 0.982; /* atualizado assincronamente */

  #slider;
  #sliderAnos;
  #sliderPct;
  #displayConsumo;
  #displayAnos;
  #displayPct;
  #displayConta;
  #btnMenos;
  #btnMais;
  #btnAnosMenos;
  #btnAnosMais;
  #btnPctMenos;
  #btnPctMais;
  #btnCalc;
  #resultado;
  #fillConsumo;
  #fillAnos;
  #fillPct;
  #thumbConsumoWrap;
  #thumbAnosWrap;
  #thumbPctWrap;
  #lightningConsumo;
  #lightningAnos;
  #lightningPct;
  #faturaPrev;
  #tarifaDisplay;
  #tarifaStatus;
  #ultimoCalc = null;
  #lightningTimer = null;

  constructor() {
    this.#slider          = document.getElementById('slider-consumo');
    this.#sliderAnos      = document.getElementById('slider-anos');
    this.#sliderPct       = document.getElementById('slider-pct');
    this.#displayConsumo  = document.getElementById('valor-consumo');
    this.#displayAnos     = document.getElementById('valor-anos');
    this.#displayPct      = document.getElementById('valor-pct');
    this.#displayConta    = document.getElementById('display-conta');
    this.#btnMenos        = document.getElementById('btn-menos');
    this.#btnMais         = document.getElementById('btn-mais');
    this.#btnAnosMenos    = document.getElementById('btn-anos-menos');
    this.#btnAnosMais     = document.getElementById('btn-anos-mais');
    this.#btnPctMenos     = document.getElementById('btn-pct-menos');
    this.#btnPctMais      = document.getElementById('btn-pct-mais');
    this.#btnCalc         = document.getElementById('btn-calcular');
    this.#resultado       = document.getElementById('calc-resultado');
    this.#fillConsumo     = document.getElementById('fill-consumo');
    this.#fillAnos        = document.getElementById('fill-anos');
    this.#fillPct         = document.getElementById('fill-pct');
    this.#thumbConsumoWrap= document.getElementById('thumb-consumo-wrap');
    this.#thumbAnosWrap   = document.getElementById('thumb-anos-wrap');
    this.#thumbPctWrap    = document.getElementById('thumb-pct-wrap');
    this.#lightningConsumo= document.getElementById('lightning-consumo');
    this.#lightningAnos   = document.getElementById('lightning-anos');
    this.#lightningPct    = document.getElementById('lightning-pct');
    this.#faturaPrev      = document.getElementById('fatura-preview');
    this.#tarifaDisplay   = document.getElementById('tarifa-display');
    this.#tarifaStatus    = document.getElementById('tarifa-status');

    this.#bind();
    this.#syncSlider(this.#slider, this.#fillConsumo, this.#thumbConsumoWrap, 50, 2000);
    this.#syncSliderAnos();
    this.#syncSliderPct();
    this.#atualizarConta();
    this.#carregarTarifa();
  }

  async #carregarTarifa() {
    const { valor, fonte } = await TarifaService.obter();
    CalculadoraController.#TARIFA_KWH = valor;
    this.#atualizarConta();
    this.#atualizarPreviewFatura();
    if (this.#tarifaDisplay) {
      this.#tarifaDisplay.innerHTML =
        TarifaService.formatar(valor).replace('R$ ', 'R$ ') +
        '<span class="calc-tarifa-unit">/kWh</span>';
    }
    if (this.#tarifaStatus) {
      this.#tarifaStatus.textContent = fonte === 'api' ? '✓ ao vivo' : fonte === 'cache' ? '⏱ cache' : '● fallback';
      this.#tarifaStatus.className   = 'calc-tarifa-status calc-tarifa-status--' + fonte;
    }
    this.#atualizarPreviewFatura();
  }

  #bind() {
    this.#slider.addEventListener('input', () => {
      this.#syncSlider(this.#slider, this.#fillConsumo, this.#thumbConsumoWrap, 50, 2000);
      this.#atualizarConta();
      this.#atualizarPreviewFatura();
      this.#dispararRaios(this.#lightningConsumo);
    });
    this.#sliderAnos.addEventListener('input', () => {
      this.#syncSliderAnos();
      this.#dispararRaios(this.#lightningAnos);
    });

    this.#btnMenos.addEventListener('click', () => {
      this.#slider.value = Math.max(50, +this.#slider.value - 10);
      this.#syncSlider(this.#slider, this.#fillConsumo, this.#thumbConsumoWrap, 50, 2000);
      this.#atualizarConta();
      this.#atualizarPreviewFatura();
      this.#dispararRaios(this.#lightningConsumo);
    });
    this.#btnMais.addEventListener('click', () => {
      this.#slider.value = Math.min(2000, +this.#slider.value + 10);
      this.#syncSlider(this.#slider, this.#fillConsumo, this.#thumbConsumoWrap, 50, 2000);
      this.#atualizarConta();
      this.#atualizarPreviewFatura();
      this.#dispararRaios(this.#lightningConsumo);
    });
    this.#btnAnosMenos.addEventListener('click', () => {
      this.#sliderAnos.value = Math.max(1, +this.#sliderAnos.value - 1);
      this.#syncSliderAnos();
      this.#dispararRaios(this.#lightningAnos);
    });
    this.#btnAnosMais.addEventListener('click', () => {
      this.#sliderAnos.value = Math.min(40, +this.#sliderAnos.value + 1);
      this.#syncSliderAnos();
      this.#dispararRaios(this.#lightningAnos);
    });

    this.#sliderPct.addEventListener('input', () => {
      this.#syncSliderPct();
      this.#dispararRaios(this.#lightningPct);
    });
    this.#btnPctMenos.addEventListener('click', () => {
      this.#sliderPct.value = Math.max(1, +this.#sliderPct.value - 1);
      this.#syncSliderPct();
      this.#dispararRaios(this.#lightningPct);
    });
    this.#btnPctMais.addEventListener('click', () => {
      this.#sliderPct.value = Math.min(15, +this.#sliderPct.value + 1);
      this.#syncSliderPct();
      this.#dispararRaios(this.#lightningPct);
    });

    this.#btnCalc.addEventListener('click', () => this.#calcular());
  }

  #syncSlider(slider, fill, thumbWrap, min, max) {
    const v   = +slider.value;
    const pct = ((v - min) / (max - min) * 100);
    if (fill)      fill.style.width      = pct + '%';
    if (thumbWrap) thumbWrap.style.left  = pct + '%';
    slider.style.setProperty('--slider-pct', pct.toFixed(1) + '%');
    if (slider === this.#slider && this.#displayConsumo) {
      this.#displayConsumo.textContent = v;
    }
  }

  #syncSliderAnos() {
    const v   = +this.#sliderAnos.value;
    const pct = ((v - 1) / (40 - 1) * 100);
    if (this.#fillAnos)       this.#fillAnos.style.width      = pct + '%';
    if (this.#thumbAnosWrap)  this.#thumbAnosWrap.style.left  = pct + '%';
    this.#sliderAnos.style.setProperty('--slider-pct', pct.toFixed(1) + '%');
    if (this.#displayAnos) this.#displayAnos.textContent = v;
  }

  #syncSliderPct() {
    const v   = +this.#sliderPct.value;
    const pct = ((v - 1) / (15 - 1) * 100);
    if (this.#fillPct)      this.#fillPct.style.width     = pct + '%';
    if (this.#thumbPctWrap) this.#thumbPctWrap.style.left = pct + '%';
    this.#sliderPct.style.setProperty('--slider-pct', pct.toFixed(1) + '%');
    if (this.#displayPct) this.#displayPct.textContent = v;
  }

  #atualizarConta() {
    if (!this.#displayConta) return;
    const consumo = +this.#slider.value;
    const fatura  = consumo * CalculadoraController.#TARIFA_KWH;
    this.#displayConta.textContent = fatura.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  }

  #atualizarPreviewFatura() {
    if (!this.#faturaPrev) return;
    const consumo = +this.#slider.value;
    const fatura  = consumo * CalculadoraController.#TARIFA_KWH;
    this.#faturaPrev.textContent = '≈ ' + CalculadoraController.#fmt(fatura) + ' / mês';
  }

  #dispararRaios(container) {
    if (!container) return;
    clearTimeout(this.#lightningTimer);
    container.innerHTML = '';
    const n = Math.floor(Math.random() * 3) + 2;
    for (let i = 0; i < n; i++) {
      const bolt = document.createElement('span');
      bolt.className   = 'lightning-bolt';
      bolt.textContent = '⚡';
      bolt.style.cssText = `left:${10 + Math.random() * 80}%;animation-delay:${(Math.random() * 0.3).toFixed(2)}s`;
      container.appendChild(bolt);
    }
    container.classList.add('active');
    this.#lightningTimer = setTimeout(() => {
      container.classList.remove('active');
      container.innerHTML = '';
    }, 700);
  }

  #calcular() {
    const consumo = +this.#slider.value;
    const anos    = +this.#sliderAnos.value;
    const tarifa  = CalculadoraController.#TARIFA_KWH;
    const taxa    = +this.#sliderPct.value / 100;

    const faturaMensal = consumo * tarifa;
    const faturaAnual  = faturaMensal * 12;
    let   acumulado    = 0;
    const anoAtual     = new Date().getFullYear();
    const linhasAnos   = [];

    for (let a = 1; a <= anos; a++) {
      const valorAno = faturaAnual * Math.pow(1 + taxa, a - 1);
      acumulado += valorAno;
      linhasAnos.push({ ano: a, ano_cal: anoAtual + a - 1, valor: valorAno, acumulado });
    }

    const pontos = linhasAnos.filter(l =>
      l.ano <= 5 || l.ano === 10 || l.ano === 15 || l.ano === 20 ||
      l.ano === 25 || l.ano === 30 || l.ano === anos
    );
    const dedup = [...new Map(pontos.map(l => [l.ano, l])).values()];
    const retorno = faturaMensal > 0 ? (25000 / faturaMensal).toFixed(1) : '—';

    this.#ultimoCalc = {
      consumo, anos, tarifa, taxa,
      faturaMensal, faturaAnual, acumulado, retornoMeses: retorno,
      economia_mensal:  CalculadoraController.#fmt(faturaMensal),
      economia_anual:   CalculadoraController.#fmt(faturaAnual),
      economia_periodo: CalculadoraController.#fmt(acumulado),
      investimento:     'R$ 25.000,00',
      linhas: dedup.map(l => ({
        ano: l.ano, ano_cal: l.ano_cal,
        valorFmt: CalculadoraController.#fmt(l.valor),
        acumuladoFmt: CalculadoraController.#fmt(l.acumulado),
      })),
    };

    const tabelaLinhas = dedup.map(l => `
      <tr>
        <td>Ano ${l.ano} (${l.ano_cal})</td>
        <td>${CalculadoraController.#fmt(l.valor)}</td>
        <td class="td-acum">${CalculadoraController.#fmt(l.acumulado)}</td>
      </tr>`).join('');

    this.#resultado.innerHTML = `
      <div class="calc-kpi-row">
        <div class="calc-kpi">
          <div class="calc-kpi-label">Fatura Mensal</div>
          <div class="calc-kpi-valor">${CalculadoraController.#fmt(faturaMensal)}</div>
        </div>
        <div class="calc-kpi">
          <div class="calc-kpi-label">Economia Anual</div>
          <div class="calc-kpi-valor">${CalculadoraController.#fmt(faturaAnual)}</div>
        </div>
        <div class="calc-kpi calc-kpi--destaque">
          <div class="calc-kpi-label">Economia em ${anos} Anos</div>
          <div class="calc-kpi-valor">${CalculadoraController.#fmt(acumulado)}</div>
        </div>
        <div class="calc-kpi calc-kpi--retorno">
          <div class="calc-kpi-label">Retorno do Invest.</div>
          <div class="calc-kpi-valor">${retorno} meses</div>
        </div>
      </div>
      <div class="calc-tabela-wrap">
        <table class="calc-tabela">
          <thead><tr><th>Período</th><th>Economia/Ano</th><th>Acumulado</th></tr></thead>
          <tbody>${tabelaLinhas}</tbody>
        </table>
      </div>
      <div class="calc-result-actions">
        <button id="btn-usar-orcamento" class="btn-usar-orcamento">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/></svg>
          Usar no Orçamento
        </button>
      </div>
      <div class="calc-explicacao">
        <strong>Metodologia:</strong> Tarifa Enel SP R$${tarifa.toFixed(3)}/kWh com crescimento tarifário de
        ${(taxa*100).toFixed(0)}% a.a. Consumo de ${consumo} kWh/mês gera fatura de
        ${CalculadoraController.#fmt(faturaMensal)}/mês. Retorno estimado com sistema de
        ~R$25.000: <strong>${retorno} meses</strong>. Cálculo conforme resolução ANEEL vigente.
      </div>`;

    this.#resultado.classList.add('is-visible');
    document.getElementById('btn-usar-orcamento').addEventListener('click', () => this.#preencherFormulario());
  }

  #preencherFormulario() {
    if (!this.#ultimoCalc) return;
    const c   = this.#ultimoCalc;
    const set = (id, val) => { const el = document.getElementById(id); if (el) el.value = val; };
    set('economia_mensal', c.economia_mensal);
    set('economia_anual',  c.economia_anual);
    set('economia_30',     c.economia_periodo);
    set('periodo_anos',    c.anos + ' anos');
    set('investimento',    c.investimento);
    set('inflacao',        (c.taxa * 100).toFixed(0) + '% a.a.');
    set('economia',        `${c.consumo} kWh/mês — Retorno em ${c.retornoMeses} meses`);
    document.querySelectorAll('[data-tela="formulario"]')[0]?.click();
  }

  getUltimoCalc() { return this.#ultimoCalc; }

  static #fmt(v) {
    return v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  }
}
/* ===================================================
   INSTALAÇÃO PWA (banner "Adicionar à tela inicial")
   Comportamento:
     - Aparece no TOPO IMEDIATAMENTE a cada nova sessão
     - Botão ✕ fecha só na sessão atual; volta na próxima visita
     - Desaparece permanentemente apenas quando o app for instalado
     - Se o browser não suportar beforeinstallprompt: exibe instrução manual
   =================================================== */
class PwaInstallController {
  static #INSTALLED_KEY = 'efv_pwa_installed';
  #deferredPrompt = null;
  #banner;
  #btnInstall;
  #btnDismiss;

  constructor() {
    this.#banner     = document.getElementById('pwa-banner');
    this.#btnInstall = document.getElementById('pwa-install-btn');
    this.#btnDismiss = document.getElementById('pwa-dismiss-btn');
    this.#bind();
  }

  #bind() {
    /* Ocultar permanentemente só se o app já estiver instalado */
    const jaInstalado = window.matchMedia('(display-mode: standalone)').matches
      || window.navigator.standalone === true
      || !!localStorage.getItem(PwaInstallController.#INSTALLED_KEY);
    if (jaInstalado) return;

    /* Mostrar banner IMEDIATAMENTE — não aguardar beforeinstallprompt */
    this.#banner.hidden = false;

    /* Captura o prompt nativo quando disponível */
    window.addEventListener('beforeinstallprompt', e => {
      e.preventDefault();
      this.#deferredPrompt = e;
    });

    window.addEventListener('appinstalled', () => {
      this.#fecharDefinitivo();
    });

    this.#btnInstall.addEventListener('click', async () => {
      if (this.#deferredPrompt) {
        /* Chrome / Edge: usa o prompt nativo */
        this.#deferredPrompt.prompt();
        const { outcome } = await this.#deferredPrompt.userChoice;
        this.#deferredPrompt = null;
        if (outcome === 'accepted') {
          this.#fecharDefinitivo();
        } else {
          this.#fecharSessao();
        }
      } else {
        /* Safari / Firefox: orienta instalação manual */
        alert('Para instalar: use o menu do navegador → "Adicionar à tela inicial" ou "Instalar aplicativo".');
      }
    });

    this.#btnDismiss.addEventListener('click', () => this.#fecharSessao());
  }

  /* Fecha só nesta sessão — banner volta na próxima visita */
  #fecharSessao() {
    this.#banner.classList.add('pwa-banner--saindo');
    setTimeout(() => {
      this.#banner.hidden = true;
      this.#banner.classList.remove('pwa-banner--saindo');
    }, 380);
  }

  /* Fecha permanentemente — app foi instalado */
  #fecharDefinitivo() {
    localStorage.setItem(PwaInstallController.#INSTALLED_KEY, '1');
    this.#banner.hidden = true;
    this.#deferredPrompt = null;
  }
}

/* ===================================================
   COMPARTILHAMENTO (WhatsApp / E-mail / Telegram / Print)
   =================================================== */
class ShareController {
  #modal;
  #btnClose;
  #btnWhatsApp;
  #btnEmail;
  #btnTelegram;
  #btnPrint;
  #btnDownload;
  #htmlAtual = null;
  #nomeAtual = '';

  constructor() {
    this.#modal      = document.getElementById('share-modal');
    this.#btnClose   = document.getElementById('share-modal-close');
    this.#btnWhatsApp= document.getElementById('share-whatsapp');
    this.#btnEmail   = document.getElementById('share-email');
    this.#btnTelegram= document.getElementById('share-telegram');
    this.#btnPrint    = document.getElementById('share-print');
    this.#btnDownload = document.getElementById('share-download');
    this.#bind();
  }

  #bind() {
    this.#btnClose.addEventListener('click',   () => this.fechar());
    this.#modal.addEventListener('click', e => { if (e.target === this.#modal) this.fechar(); });
    document.addEventListener('keydown', e => { if (e.key === 'Escape') this.fechar(); });

    this.#btnWhatsApp.addEventListener('click', () => this.#compartilharWhatsApp());
    this.#btnEmail.addEventListener('click',    () => this.#compartilharEmail());
    this.#btnTelegram.addEventListener('click', () => this.#compartilharTelegram());
    this.#btnPrint.addEventListener('click',    () => this.#imprimir());
    this.#btnDownload?.addEventListener('click', () => this.#baixarPDF());
  }

  abrir(htmlPDF, nome) {
    this.#htmlAtual = htmlPDF;
    this.#nomeAtual = nome || 'Orçamento EFV Solar';
    this.#modal.setAttribute('aria-hidden', 'false');
    this.#modal.classList.add('is-open');
    this.#btnClose.focus();
  }

  fechar() {
    this.#modal.setAttribute('aria-hidden', 'true');
    this.#modal.classList.remove('is-open');
  }

  #textoResumo() {
    return `Orçamento EFV Solar — ${this.#nomeAtual}\nProfissional: Lino M. DE AZEVEDO | (11) 97239-5317\nhttps://www.instagram.com/efvsolar_oficia`;
  }

  /* Baixa o orçamento como arquivo HTML silenciosamente (sem popup) */
  #downloadSilencioso() {
    if (!this.#htmlAtual) return;
    const nomeLimpo = this.#nomeAtual.replace(/[^a-z0-9]/gi, '-').toLowerCase() || 'orcamento';
    const blob = new Blob([this.#htmlAtual], { type: 'text/html;charset=utf-8' });
    const url  = URL.createObjectURL(blob);
    const a    = document.createElement('a');
    a.href     = url;
    a.download = `orcamento-efv-solar-${nomeLimpo}.html`;
    a.style.display = 'none';
    document.body.appendChild(a);
    a.click();
    setTimeout(() => { URL.revokeObjectURL(url); document.body.removeChild(a); }, 1200);
  }

  async #compartilharWhatsApp() {
    if (!this.#htmlAtual) return;

    /* Sempre baixa o arquivo primeiro */
    this.#downloadSilencioso();

    const blob = new Blob([this.#htmlAtual], { type: 'text/html;charset=utf-8' });
    const file = new File([blob], 'orcamento-efv-solar.html', { type: 'text/html' });

    /* Web Share API nativa (Android/iOS) — abre painel com WhatsApp */
    if (navigator.canShare?.({ files: [file] })) {
      try {
        await navigator.share({
          files: [file],
          title: `Orçamento EFV Solar — ${this.#nomeAtual}`,
          text:  `Orçamento gerado pela EFV Solar\nProfissional: Lino M. DE AZEVEDO | (11) 97239-5317`,
        });
        return;
      } catch (e) {
        if (e.name === 'AbortError') return;
      }
    }

    /* Fallback desktop: arquivo já baixado, abre WA com instrução de anexo */
    const msg = encodeURIComponent(
      `Orçamento EFV Solar — ${this.#nomeAtual}\n` +
      `Profissional: Lino M. DE AZEVEDO | (11) 97239-5317\n` +
      `📎 Arquivo baixado automaticamente — anexe ao WhatsApp.`
    );
    setTimeout(() => window.open(`https://api.whatsapp.com/send?text=${msg}`, '_blank', 'noopener'), 900);
  }

  #compartilharEmail() {
    if (!this.#htmlAtual) return;

    /* Baixa o arquivo antes de abrir o cliente de e-mail */
    this.#downloadSilencioso();

    const sub = encodeURIComponent(`Orçamento EFV Solar — ${this.#nomeAtual}`);
    const bod = encodeURIComponent(
      `Olá,\n\n` +
      `Segue o orçamento de instalação fotovoltaica da EFV Solar.\n\n` +
      `📎 O arquivo do orçamento foi baixado automaticamente no seu dispositivo — ` +
      `por favor, anexe-o a este e-mail.\n\n` +
      `Profissional: Lino M. DE AZEVEDO\n` +
      `Telefone: (11) 97239-5317\n` +
      `Instagram: @efvsolar_oficia`
    );
    setTimeout(() => { window.location.href = `mailto:?subject=${sub}&body=${bod}`; }, 900);
  }

  #compartilharTelegram() {
    const msg = encodeURIComponent(this.#textoResumo());
    window.open(`https://t.me/share/url?url=https://efvsolar.com.br&text=${msg}`, '_blank', 'noopener');
  }

  #imprimir() {
    if (!this.#htmlAtual) return;
    const win = window.open('', '_blank');
    if (!win) { alert('Permita pop-ups para imprimir/salvar o PDF.'); return; }
    win.document.write(this.#htmlAtual);
    win.document.close();
    win.addEventListener('load', () => setTimeout(() => win.print(), 400));
  }

  #baixarPDF() {
    /* Usa o dialogo de impressão nativo para salvar como PDF — funciona offline */
    if (!this.#htmlAtual) return;
    const win = window.open('', '_blank');
    if (!win) { alert('Permita pop-ups para salvar o PDF.'); return; }
    win.document.write(this.#htmlAtual);
    win.document.close();
    win.addEventListener('load', () => setTimeout(() => win.print(), 400));
  }
}

/* ===================================================
   TYPEWRITER EFFECT
   =================================================== */
class TypewriterEffect {
  #el;
  #fullText;
  #charIdx  = 0;
  #timerId  = null;
  static #START_DELAY   = 1500;
  static #CHAR_INTERVAL = 52;

  constructor(selector) {
    this.#el = document.querySelector(selector);
    if (!this.#el) return;
    this.#fullText = this.#el.textContent;
    this.#el.textContent = '';
    this.#el.classList.add('home-tagline--typing');
    this.#timerId = setTimeout(() => this.#type(), TypewriterEffect.#START_DELAY);
  }

  #type() {
    if (this.#charIdx >= this.#fullText.length) {
      this.#el.classList.remove('home-tagline--typing');
      return;
    }
    this.#el.textContent = this.#fullText.slice(0, ++this.#charIdx);
    this.#el.classList.add('home-tagline--typing');
    this.#timerId = setTimeout(() => this.#type(), TypewriterEffect.#CHAR_INTERVAL);
  }

  destroy() {
    if (this.#timerId) { clearTimeout(this.#timerId); this.#timerId = null; }
  }
}

/* ===================================================
   APLICAÇÃO PRINCIPAL
   =================================================== */
class EfvSolarApp {
  #logoBase64          = null;
  #btnGerar            = null;
  #menuController      = null;
  #router              = null;
  #orcamentosCtrl      = null;
  #financasCtrl        = null;
  #calculadoraCtrl     = null;
  #shareCtrl           = null;
  #pwaCtrl             = null;
  #animacao            = null;
  #typewriter          = null;
  #sheetAberto         = false;

  constructor() {
    this.#btnGerar = document.getElementById('btn-gerar-pdf');
    this.#init();
  }

  async #init() {
    this.#logoBase64      = await EfvSolarApp.#carregarImagemBase64('./assets/efv_solar.png');
    this.#menuController  = new MenuController();
    this.#orcamentosCtrl  = new OrcamentosController(this.#logoBase64);
    this.#financasCtrl    = new FinancasController();
    this.#calculadoraCtrl = new CalculadoraController();
    this.#shareCtrl       = new ShareController();
    this.#orcamentosCtrl.setShareCtrl(this.#shareCtrl);
    this.#router          = new Router(tela => this.#aoNavegar(tela));
    this.#pwaCtrl         = new PwaInstallController();
    const canvas = document.getElementById('solar-canvas');
    if (canvas) this.#animacao = new AnimationController(canvas);
    this.#typewriter = new TypewriterEffect('.home-tagline');
    this.#vincularEventos();
    EfvSolarApp.#registrarServiceWorker();
  }

  #aoNavegar(tela) {
    this.#menuController.fechar();
    /* Se navegou para fora do formulário enquanto a sheet estava aberta: fecha silenciosamente */
    if (this.#sheetAberto && tela !== 'formulario') {
      document.body.classList.remove('sheet-open', 'sheet-closing');
      this.#sheetAberto = false;
    }
    if (tela === 'orcamentos') this.#orcamentosCtrl.render();
    if (tela === 'financas')   this.#financasCtrl.render();
  }

  /* LOGO EMBUTIDO — app funciona sem servidor (file://) */
  static #LOGO_B64 = 'data:image/png;base64,';

  static async #carregarImagemBase64(_src) {
    return EfvSolarApp.#LOGO_B64;
  }

  #vincularEventos() {
    this.#btnGerar.addEventListener('click', () => this.#salvarEGerarPDF());

    /* Home: abrir sheet ao clicar em Novo Orçamento */
    document.getElementById('btn-novo-orcamento')
      ?.addEventListener('click', () => this.#abrirSheet());

    /* Sheet: fechar ao clicar no X */
    document.getElementById('btn-fechar-sheet')
      ?.addEventListener('click', () => this.#fecharSheet());

    /* Sheet: fechar ao clicar no backdrop */
    document.getElementById('sheet-backdrop')
      ?.addEventListener('click', () => this.#fecharSheet());

    /* Home: reiniciar animação */
    document.getElementById('btn-ver-animacao')
      ?.addEventListener('click', () => this.#animacao?.reiniciar());
  }

  /* Abre a sheet: canvas dimma, formulário sobe como bottom sheet */
  #abrirSheet() {
    if (this.#sheetAberto) return;
    this.#sheetAberto = true;
    this.#animacao?.pausar();
    document.body.classList.add('sheet-open');
    this.#router.navegar('formulario');
  }

  /* Fecha a sheet com animação de slide-down */
  #fecharSheet() {
    if (!this.#sheetAberto) return;
    document.body.classList.add('sheet-closing');
    setTimeout(() => {
      document.body.classList.remove('sheet-open', 'sheet-closing');
      this.#sheetAberto = false;
      this.#animacao?.retomar();
      this.#router.navegar('home');
    }, 270);
  }

  #coletarDados() {
    return FIELDS.map(({ id, label, section }) => ({
      label,
      section,
      value: document.getElementById(id)?.value?.trim() ?? '',
    }));
  }

  #setCarregando(ativo) {
    this.#btnGerar.disabled = ativo;
    const lblEl = this.#btnGerar.querySelector('.btn-label');
    if (lblEl) lblEl.textContent = ativo ? 'Salvando...' : 'Salvar e Gerar PDF';
    this.#btnGerar.classList.toggle('loading', ativo);
  }

  async #salvarEGerarPDF() {
    this.#setCarregando(true);
    try {
      const dados     = this.#coletarDados();
      const nomeField = dados.find(d => d.label === 'Nome do Cliente');
      const nome      = nomeField?.value || '';

      const registro = {
        id:             Date.now().toString(36) + Math.random().toString(36).slice(2),
        nome,
        data:           new Date().toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' }),
        dados,
        ok:             false,
        economia_mensal: dados.find(d => d.label === 'Economia Mensal')?.value ?? '',
        economia_anual:  dados.find(d => d.label === 'Economia Anual')?.value  ?? '',
        investimento:    dados.find(d => d.label === 'Investimento')?.value    ?? '',
      };

      OrcamentoStorage.salvar(registro);

      const htmlPDF = PrintBuilder.build(dados, this.#logoBase64);
      document.getElementById('orcamento-form').reset();
      this.#fecharSheet();

      /* Abre modal de compartilhamento — download/WA/Email/Imprimir */
      this.#shareCtrl.abrir(htmlPDF, nome);
    } finally {
      this.#setCarregando(false);
    }
  }

  static async #registrarServiceWorker() {
    if ('serviceWorker' in navigator) {
      try { await navigator.serviceWorker.register('./sw.js'); }
      catch { /* SW não crítico */ }
    }
  }
}

/* ===== CONSTRUTOR DO PDF ===== */
class PrintBuilder {
  static #INSTAGRAM_URL  = 'https://www.instagram.com/efvsolar_oficia';
  static #PROFISSIONAL   = 'Lino M. DE AZEVEDO';
  static #TELEFONE       = '(11) 97239-5317';

  static #INSTAGRAM_SVG = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24"
    fill="none" stroke="currentColor" stroke-width="2"
    stroke-linecap="round" stroke-linejoin="round" width="34" height="34">
    <rect x="2" y="2" width="20" height="20" rx="5" ry="5"/>
    <path d="M16 11.37A4 4 0 1 1 12.63 8 4 4 0 0 1 16 11.37z"/>
    <line x1="17.5" y1="6.5" x2="17.51" y2="6.5"/>
  </svg>`;

  /* Ponto de entrada: monta o HTML completo do PDF */
  static build(dados, logoBase64, calcData = null) {
    const date     = new Date().toLocaleDateString('pt-BR', { day: '2-digit', month: 'long', year: 'numeric' });
    const conteudo = PrintBuilder.#montarSecoes(dados) + (calcData ? PrintBuilder.#montarCalcSection(calcData) : '');
    return PrintBuilder.#montarDocumento({ date, conteudo, logoBase64 });
  }

  /* Seção de cálculo financeiro — aparece no PDF quando gerado pela calculadora */
  static #montarCalcSection(c) {
    const tabelaLinhas = c.linhas.map(l => `
      <tr>
        <td>Ano ${l.ano} (${l.ano_cal})</td>
        <td>${l.valorFmt}</td>
        <td class="td-acum">${l.acumuladoFmt}</td>
      </tr>`).join('');

    return `
      <div class="calc-section-pdf">
        <h3 class="secao-titulo">Análise de Economia Solar — Projeção ${c.anos} Anos</h3>
        <div class="calc-kpi-pdf">
          <div class="calc-kpi-pdf-item">
            <div class="calc-kpi-pdf-label">Fatura Mensal</div>
            <div class="calc-kpi-pdf-valor">${c.faturaMensal}</div>
          </div>
          <div class="calc-kpi-pdf-item">
            <div class="calc-kpi-pdf-label">Economia Anual</div>
            <div class="calc-kpi-pdf-valor">${c.faturaAnual}</div>
          </div>
          <div class="calc-kpi-pdf-item destaque">
            <div class="calc-kpi-pdf-label">Total ${c.anos} Anos</div>
            <div class="calc-kpi-pdf-valor">${c.acumulado}</div>
          </div>
          <div class="calc-kpi-pdf-item">
            <div class="calc-kpi-pdf-label">Retorno Invest.</div>
            <div class="calc-kpi-pdf-valor">${c.retorno} meses</div>
          </div>
        </div>
        <table class="calc-tabela-pdf">
          <thead><tr><th>Período</th><th>Economia/Ano</th><th>Acumulado</th></tr></thead>
          <tbody>${tabelaLinhas}</tbody>
        </table>
        <div class="calc-nota-pdf">
          Tarifa Enel SP R${c.tarifa}/kWh · crescimento tarifário ${c.taxa}% a.a. ·
          Consumo ${c.consumo} kWh/mês · Sistema estimado ~R$25.000.
          Cálculo conforme resolução ANEEL vigente.
        </div>
      </div>`;
  }

  /* Agrupa campos por seção e gera o HTML de cada bloco */
  static #montarSecoes(dados) {
    const agrupado = dados.reduce((acc, item) => {
      (acc[item.section] ??= []).push(item);
      return acc;
    }, {});

    return Object.entries(agrupado).map(([secao, itens]) => {
      const titulo = SECTIONS[secao] ?? secao;
      const linhas = itens.map(({ label, value }) => `
        <tr>
          <td class="label-cell">${label}</td>
          <td class="value-cell">${PrintBuilder.#escapar(value) || '<em class="vazio">—</em>'}</td>
        </tr>`).join('');

      return `
        <div class="bloco-secao">
          <h3 class="secao-titulo">${titulo}</h3>
          <table class="tabela-dados"><tbody>${linhas}</tbody></table>
        </div>`;
    }).join('');
  }

  /* Escapa caracteres HTML para evitar injeção no documento de impressão */
  static #escapar(str) {
    return String(str)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  /* Monta o documento HTML completo com marca d'água, conteúdo e rodapé */
  static #montarDocumento({ date, conteudo, logoBase64 }) {
    const marcaDagua  = logoBase64 ? `<img src="${logoBase64}" class="marca-dagua" alt="">` : '';
    const logoHeader  = logoBase64 ? `<img src="${logoBase64}" class="logo-header"  alt="EFV Solar">` : '';

    return `<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Orçamento EFV Solar — ${date}</title>
  <style>
    @page {
      size: A4 portrait;
      margin: 1.6cm 1.4cm 1.8cm 1.4cm;
    }

    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

    :root {
      --gold: #FFB800;
      --dark: #111827;
      --gray: #374151;
      --border: #E5E7EB;
    }

    html, body {
      width: 100%;
      font-family: 'Segoe UI', Arial, sans-serif;
      font-size: 11pt;
      color: #111;
      background: #fff;
    }

    /* ---- BANNER INSTRUÇÃO (apenas tela, oculto na impressão) ---- */
    .pdf-instrucao {
      display: flex;
      align-items: center;
      gap: 10px;
      background: #fffbeb;
      border: 1.5px solid #FFB800;
      border-radius: 8px;
      padding: 10px 14px;
      margin-bottom: 18px;
      font-size: 13px;
      color: #6B4F00;
    }
    .pdf-instrucao-icon { font-size: 22px; flex-shrink: 0; }
    .pdf-instrucao strong { color: #111; }

    /* ---- MARCA D'ÁGUA ---- */
    .marca-dagua {
      position: fixed;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      width: 65%;
      opacity: 0.10;
      z-index: 0;
      pointer-events: none;
      background-repeat: no-repeat;
    }

    /* ---- CONTEÚDO ---- */
    .conteudo {
      position: relative;
      z-index: 1;
      width: 100%;
    }

    /* ---- CABEÇALHO ---- */
    .cabecalho {
      display: flex;
      align-items: center;
      gap: 14px;
      padding-bottom: 12px;
      border-bottom: 3px solid var(--gold);
      margin-bottom: 20px;
    }
    .logo-header {
      width: 68px;
      height: 68px;
      object-fit: contain;
      flex-shrink: 0;
    }
    .cabecalho-texto h1 {
      font-size: 22pt;
      font-weight: 900;
      color: var(--gold);
      letter-spacing: 4px;
      text-transform: uppercase;
    }
    .cabecalho-texto .subtitulo {
      font-size: 9pt;
      color: #6B7280;
      letter-spacing: 2px;
      text-transform: uppercase;
      margin-top: 2px;
    }
    .cabecalho-texto .data {
      font-size: 8.5pt;
      color: #9CA3AF;
      margin-top: 4px;
    }

    /* ---- SEÇÕES ---- */
    .bloco-secao {
      margin-bottom: 16px;
      break-inside: avoid;
    }
    .secao-titulo {
      background: var(--dark);
      color: var(--gold);
      font-size: 9pt;
      font-weight: 700;
      padding: 7px 12px;
      text-transform: uppercase;
      letter-spacing: 1.5px;
      border-radius: 4px 4px 0 0;
    }
    .tabela-dados {
      width: 100%;
      border-collapse: collapse;
      border: 1px solid var(--border);
      border-top: none;
    }
    .tabela-dados tr:nth-child(even) { background: #f7f8f9; }
    .tabela-dados td {
      padding: 7px 12px;
      border-bottom: 1px solid var(--border);
      font-size: 10pt;
      vertical-align: top;
    }
    .label-cell {
      font-weight: 700;
      color: var(--gray);
      width: 40%;
      border-right: 1px solid var(--border);
    }
    .value-cell { color: #111; }
    .vazio { color: #bbb; font-style: italic; }

    /* ---- SEÇÃO CÁLCULO (se presente) ---- */
    .calc-section-pdf {
      margin-bottom: 16px;
      break-inside: avoid;
    }
    .calc-kpi-pdf {
      display: flex;
      gap: 10px;
      margin-bottom: 14px;
      flex-wrap: wrap;
    }
    .calc-kpi-pdf-item {
      flex: 1;
      min-width: 120px;
      background: var(--dark);
      color: #fff;
      border-radius: 6px;
      padding: 10px 8px;
      text-align: center;
      border: 1.5px solid rgba(255,184,0,0.25);
    }
    .calc-kpi-pdf-item.destaque { border-color: #22c55e; }
    .calc-kpi-pdf-label {
      font-size: 7.5pt;
      color: #9CA3AF;
      text-transform: uppercase;
      letter-spacing: 1px;
      margin-bottom: 4px;
    }
    .calc-kpi-pdf-valor {
      font-size: 12pt;
      font-weight: 900;
      color: var(--gold);
    }
    .calc-kpi-pdf-item.destaque .calc-kpi-pdf-valor { color: #4ade80; }

    .calc-tabela-pdf {
      width: 100%;
      border-collapse: collapse;
      font-size: 9pt;
    }
    .calc-tabela-pdf th {
      background: var(--dark);
      color: var(--gold);
      padding: 6px 10px;
      text-align: left;
      font-size: 8pt;
      letter-spacing: 0.5px;
    }
    .calc-tabela-pdf td {
      padding: 5px 10px;
      border-bottom: 1px solid var(--border);
    }
    .calc-tabela-pdf tr:nth-child(even) td { background: #f9fafb; }
    .td-acum { font-weight: 700; color: #16a34a; }
    .calc-nota-pdf {
      margin-top: 10px;
      font-size: 8pt;
      color: #6B7280;
      padding: 8px 10px;
      border-left: 3px solid var(--gold);
      background: #fffbeb;
      border-radius: 0 4px 4px 0;
    }

    /* ---- RODAPÉ ---- */
    .rodape {
      margin-top: 24px;
      padding-top: 12px;
      border-top: 2.5px solid var(--gold);
      display: flex;
      justify-content: space-between;
      align-items: center;
      gap: 16px;
      break-inside: avoid;
    }
    .instagram-link {
      display: flex;
      align-items: center;
      gap: 8px;
      color: #E1306C;
      text-decoration: none;
      font-weight: 700;
      font-size: 10pt;
    }
    .info-profissional {
      text-align: right;
      font-size: 9pt;
      color: #555;
      line-height: 1.8;
    }
    .info-profissional strong { color: #111; }

    /* ---- RESPONSIVO CELULAR (visualização na tela) ---- */
    @media screen and (max-width: 640px) {
      html, body { font-size: 14px; }
      body { padding: 12px; }
      .cabecalho { flex-direction: column; align-items: flex-start; gap: 8px; }
      .logo-header { width: 52px; height: 52px; }
      .cabecalho-texto h1 { font-size: 20pt; letter-spacing: 2px; }
      /* Tabela vira lista vertical no celular */
      .tabela-dados,
      .tabela-dados tbody,
      .tabela-dados tr,
      .tabela-dados td { display: block; width: 100%; }
      .tabela-dados tr { border-bottom: 1px solid var(--border); padding-bottom: 6px; }
      .tabela-dados tr:last-child { border-bottom: none; }
      .label-cell {
        border-right: none;
        border-bottom: none;
        padding-bottom: 2px;
        font-size: 11px;
        color: #888;
        text-transform: uppercase;
        letter-spacing: 0.5px;
      }
      .value-cell { padding-top: 0; font-size: 15px; font-weight: 600; }
      .calc-kpi-pdf-item { min-width: calc(50% - 5px); }
      .rodape { flex-direction: column; align-items: flex-start; gap: 10px; }
      .info-profissional { text-align: left; }
    }

    /* ---- IMPRESSÃO A4 ---- */
    @media print {
      html, body { font-size: 10.5pt; background: #fff; }
      .pdf-instrucao { display: none; }
      .marca-dagua { display: block; }
      /* Garantir que a tabela fique em formato coluna no A4 */
      .tabela-dados td { display: table-cell; }
      .tabela-dados tr { display: table-row; }
      .tabela-dados tbody { display: table-row-group; }
      .tabela-dados { display: table; }
    }
  </style>
</head>
<body>
  ${marcaDagua}

  <div class="pdf-instrucao" role="note">
    <span class="pdf-instrucao-icon">🖨️</span>
    <span>Para <strong>salvar como PDF</strong>: no diálogo de impressão, escolha o destino
    <strong>"Salvar como PDF"</strong>. Para <strong>imprimir</strong>: selecione a impressora.</span>
  </div>

  <div class="conteudo">

    <header class="cabecalho">
      ${logoHeader}
      <div class="cabecalho-texto">
        <h1>EFV SOLAR</h1>
        <p class="subtitulo">Orçamento Fotovoltaico</p>
        <p class="data">${date}</p>
      </div>
    </header>

    <main>${conteudo}</main>

    <footer class="rodape">
      <a href="${PrintBuilder.#INSTAGRAM_URL}" class="instagram-link">
        ${PrintBuilder.#INSTAGRAM_SVG}
        @efvsolar_oficia
      </a>
      <div class="info-profissional">
        <strong>Profissional:</strong> ${PrintBuilder.#PROFISSIONAL}<br>
        <strong>Contato:</strong> ${PrintBuilder.#TELEFONE}
      </div>
    </footer>

  </div>
</body>
</html>`;
  }
}

/* ===== INICIALIZAÇÃO ===== */
new EfvSolarApp();
